const queryData = $('Set Query Context2').first().json.query_data;

// Capture the LLM output as a string
const raw =
  (typeof $json.output === 'string' && $json.output) ||
  (typeof $json.text === 'string' && $json.text) ||
  (typeof $json.response === 'string' && $json.response) ||
  JSON.stringify($json);

// Parse JSON safely (handles accidental wrapping text)
function safeJsonParse(s) {
  try {
    return { ok: true, value: JSON.parse(s) };
  } catch (e) {
    const start = s.indexOf('{');
    const end = s.lastIndexOf('}');
    if (start !== -1 && end !== -1 && end > start) {
      const slice = s.slice(start, end + 1);
      try {
        return { ok: true, value: JSON.parse(slice) };
      } catch (e2) {
        return { ok: false, error: String(e2), extracted: slice };
      }
    }
    return { ok: false, error: String(e), extracted: null };
  }
}

// Canonical brand normalization map
const CANON = [
  {
    canonical: 'Marks Electrical',
    domain: 'markselectrical.co.uk',
    aliases: [
      'marks electrical',
      'markselectrical',
      'marks electrical ltd',
      'marks electrical limited',
      'markselectrical.co.uk',
      'marks electrical (markselectrical.co.uk)'
    ]
  },
  { canonical: 'AO', domain: 'ao.com', aliases: ['ao', 'ao.com', 'ao (ao.com)', 'ao.com (ao)'] },
  { canonical: 'Currys', domain: 'currys.co.uk', aliases: ['currys', 'currys pc world', 'currys pcworld', 'currys (currys.co.uk)'] },
  { canonical: 'Argos', domain: 'argos.co.uk', aliases: ['argos', 'argos (argos.co.uk)'] },
  { canonical: 'John Lewis & Partners', domain: 'johnlewis.com', aliases: ['john lewis', 'john lewis & partners', 'john lewis and partners', 'johnlewis', 'john lewis (johnlewis.com)'] },
  { canonical: 'Appliances Direct', domain: 'appliancesdirect.co.uk', aliases: ['appliances direct', 'appliance direct', 'appliancesdirect'] },
  { canonical: 'Amazon', domain: 'amazon.co.uk', aliases: ['amazon', 'amazon uk', 'amazon.co.uk', 'amazon.co.uk (amazon)'] },
  { canonical: 'Very', domain: 'very.co.uk', aliases: ['very', 'very.co.uk'] },
  { canonical: 'B&Q', domain: 'diy.com', aliases: ['b&q', 'b and q', 'bandq', 'diy.com'] },
  { canonical: 'Euronics', domain: 'euronics.co.uk', aliases: ['euronics', 'euronics uk', 'euronics.co.uk'] },
  { canonical: 'Tesco', domain: 'tesco.com', aliases: ['tesco', 'tesco.com'] },
  { canonical: 'eBay', domain: 'ebay.co.uk', aliases: ['ebay', 'ebay uk', 'ebay.co.uk'] }
];

const norm = (s) => (s || '').toString().trim().toLowerCase();

function canonicalize(name, domain) {
  const n = norm(name);
  const d = norm(domain);

  for (const b of CANON) {
    if (b.aliases.some(a => n === norm(a) || n.includes(norm(a)))) {
      return { canonical: b.canonical, domain: b.domain };
    }
    if (d && norm(b.domain) === d) {
      return { canonical: b.canonical, domain: b.domain };
    }
  }

  // fallback: strip parenthetical domain or notes
  const cleaned = (name || '').replace(/\s*\([^)]*\)\s*/g, '').trim();
  return { canonical: cleaned || (name || ''), domain: domain || '' };
}

const parsed = safeJsonParse(raw);
const data = parsed.ok ? parsed.value : null;

const ranked = Array.isArray(data?.ranked_retailers) ? data.ranked_retailers : [];

const formatCompliance =
  parsed.ok &&
  data &&
  data.country === 'UK' &&
  ranked.length === 10 &&
  ranked.every((x, i) =>
    Number.isInteger(x.rank) &&
    x.rank === i + 1 &&
    typeof x.name === 'string' &&
    typeof x.domain === 'string' &&
    typeof x.reason === 'string' &&
    typeof x.evidence_type === 'string'
  );

// Canonicalize ranked retailers
const rankedCanonical = ranked.map(item => {
  const c = canonicalize(item.name, item.domain);
  return {
    rank: item.rank,
    name_raw: item.name || '',
    domain_raw: item.domain || '',
    name: c.canonical,
    domain: c.domain || item.domain || '',
    reason: item.reason || '',
    evidence_type: item.evidence_type || 'other'
  };
});

// Client detection (robust)
const clientEntry = CANON.find(b => b.canonical === 'Marks Electrical');
const clientAliases = clientEntry ? clientEntry.aliases.map(norm) : [norm(queryData.client_name), 'marks electrical', 'markselectrical'];

const isClient = (brandOrDomain) => {
  const t = norm(brandOrDomain);
  if (!t) return false;
  if (clientAliases.some(a => a && t.includes(a))) return true;
  if (t.includes('markselectrical.co.uk')) return true;
  return false;
};

// Determine mention + position
let brandMentioned = false;
let brandPosition = null;

for (const r of rankedCanonical) {
  if (isClient(r.name) || isClient(r.domain) || isClient(r.name_raw) || isClient(r.domain_raw)) {
    brandMentioned = true;
    brandPosition = r.rank;
    break;
  }
}

// Extract competitor mentions (canonical names, in rank order, excluding client)
const competitorMentions = rankedCanonical
  .filter(r => r.name && !isClient(r.name) && !isClient(r.domain))
  .map(r => r.name);

// Dedupe competitor list but preserve order
const seen = new Set();
const competitorMentionsDedup = competitorMentions.filter(n => {
  const key = norm(n);
  if (!key) return false;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return {
  query_id: queryData.id,
  client_id: queryData.client_id,
  client_name: queryData.client_name,
  query_text: queryData.query_text,
  query_category: queryData.category,
  llm_platform: 'chatgpt',
  model_version: 'gpt-4o',
  response_raw: raw,
  response_json_ok: parsed.ok,
  response_json_error: parsed.ok ? null : parsed.error,
  response_extracted_json: parsed.ok ? null : parsed.extracted,
  response_format_compliance: formatCompliance,
  response_structured: data,
  ranked_retailers_canonical: rankedCanonical,
  brand_mentioned: brandMentioned,
  brand_position: brandPosition,
  competitor_mentions: competitorMentionsDedup,
  total_competitors_mentioned: competitorMentionsDedup.length,
  created_at: new Date().toISOString()
};

const analysisData = $('Parse LLM Response1').first().json;

// Extract deeper insights from LLM response
const rankedRetailers = analysisData.ranked_retailers_canonical || [];

// 1. Evidence Signal Deep Dive
const competitorValueProps = {};
rankedRetailers.forEach(retailer => {
  // Check if this is the client
  const isClient = retailer.name.toLowerCase().includes('marks') || 
                   retailer.name === 'Marks Electrical' ||
                   retailer.name === analysisData.client_name;

  if (isClient) return; // Skip client

  if (!competitorValueProps[retailer.name]) {
    competitorValueProps[retailer.name] = {
      total_mentions: 0,
      evidence_signals: {},
      reasons_given: []
    };
  }

  const brand = competitorValueProps[retailer.name];
  brand.total_mentions++;

  const signal = retailer.evidence_type || 'other';
  brand.evidence_signals[signal] = (brand.evidence_signals[signal] || 0) + 1;
  brand.reasons_given.push(retailer.reason);
});

// 2. What value props is client cited for?
const clientEvidence = rankedRetailers
  .filter(r => {
    const name = r.name.toLowerCase();
    return name.includes('marks') || name === 'marks electrical' || r.name === analysisData.client_name;
  })
  .map(r => r.evidence_type);

// 3. What value props do competitors use?
const competitorEvidence = rankedRetailers
  .filter(r => {
    const name = r.name.toLowerCase();
    return !(name.includes('marks') || name === 'marks electrical' || r.name === analysisData.client_name);
  })
  .map(r => r.evidence_type);

const allEvidenceTypes = [...new Set(competitorEvidence)];
const clientMissing = allEvidenceTypes.filter(e => !clientEvidence.includes(e));

// 4. Build "Why They Beat Us" analysis
const whyWeReBehind = clientMissing.map(signal => {
  const competitorsWithThis = rankedRetailers
    .filter(r => {
      const name = r.name.toLowerCase();
      const notClient = !(name.includes('marks') || name === 'marks electrical' || r.name === analysisData.client_name);
      return r.evidence_type === signal && notClient;
    })
    .slice(0, 3); // Top 3

  return {
    value_prop: signal,
    competitors_leading: competitorsWithThis.map(c => ({
      name: c.name,
      reason: c.reason,
      rank: c.rank
    })),
    opportunity: `Client should emphasize ${signal} in messaging`
  };
});

return {
  query_id: analysisData.query_id,
  client_id: analysisData.client_id,
  client_name: analysisData.client_name,
  query_text: analysisData.query_text,
  query_category: analysisData.query_category,
  llm_platform: analysisData.llm_platform,

  // Client performance
  client_visibility: {
    mentioned: analysisData.brand_mentioned,
    position: analysisData.brand_position,
    evidence_cited: clientEvidence[0] || null
  },

  // Competitor intelligence
  competitor_value_props: competitorValueProps,
  competitors_mentioned: analysisData.competitor_mentions,
  total_competitors: analysisData.total_competitors_mentioned || (analysisData.competitor_mentions ? analysisData.competitor_mentions.length : 0),

  // Gap analysis
  value_prop_gaps: whyWeReBehind,
  client_missing_signals: clientMissing,

  // Raw data
  ranked_retailers: rankedRetailers,
  llm_response_raw: analysisData.response_raw
};

const summaryData = $('Generate Summary Report').first().json;
const aggregateData = summaryData.full_data;

const finalReport = {
  executive_summary: summaryData.output,
  key_findings: summaryData.key_findings,
  competitor_analysis: summaryData.competitor_analysis,
  value_prop_gaps: summaryData.value_prop_gaps,
  recommendations: summaryData.recommendations,
  key_metrics: aggregateData.aggregate_metrics,
  competitor_landscape: aggregateData.competitor_landscape,
  performance_by_category: aggregateData.performance_by_category,
  best_performing_queries: aggregateData.best_queries,
  worst_performing_queries: aggregateData.worst_queries,
  full_aggregate_data: aggregateData
};

return finalReport;

