const analysisData = $('Analyze LLM Rankings1').first().json;
const aiResponse = $json.output || $json.text || JSON.stringify($json);

const report = {
  report_generated_at: new Date().toISOString(),
  report_type: 'LLM_Publisher_Intelligence',
  client: {
    id: analysisData.client_id,
    name: analysisData.client_name,
    query_analyzed: analysisData.query_text,
    query_category: analysisData.query_category
  },
  llm_visibility: {
    client_mentioned: analysisData.client_mentioned_by_llm,
    client_position: analysisData.client_llm_position,
    visibility_status: analysisData.visibility_status,
    competitors_mentioned: analysisData.competitors_mentioned,
    total_competitors: analysisData.total_competitors
  },
  strategic_insight: aiResponse,
  raw_data: analysisData
};

return report;

const allReports = $input.all().map(item => item.json);

// First, calculate the existing aggregate metrics
let totalPosition = 0;
let mentionCount = 0;
let top3Count = 0;
const competitorMap = {};
const categoryMap = {};

allReports.forEach(report => {
  const category = report.query_category || 'uncategorized';

  if (!categoryMap[category]) {
    categoryMap[category] = {
      total: 0,
      mentioned: 0,
      position_sum: 0,
      position_count: 0
    };
  }
  categoryMap[category].total++;

  // Track mentions - safely access client_visibility
  const clientMentioned = report.client_visibility?.mentioned || false;
  const clientPosition = report.client_visibility?.position || null;

  if (clientMentioned) {
    mentionCount++;
    categoryMap[category].mentioned++;

    if (clientPosition) {
      totalPosition += clientPosition;
      categoryMap[category].position_sum += clientPosition;
      categoryMap[category].position_count++;

      if (clientPosition <= 3) {
        top3Count++;
      }
    }
  }

  // Track competitors - safely access competitors_mentioned
  const competitorsList = report.competitors_mentioned || [];
  const seenInQuery = new Set();

  competitorsList.forEach(competitor => {
    const name = (competitor || "").trim();
    if (!name) return;

    const key = name.toLowerCase();
    if (seenInQuery.has(key)) return;
    seenInQuery.add(key);

    if (key !== "markselectrical" && key !== "marks electrical" && !key.includes("marks")) {
      competitorMap[name] = (competitorMap[name] || 0) + 1;
    }
  });
});

// Aggregate evidence signal patterns
const evidenceSignalMap = {
  price: { count: 0, brands: new Set(), sample_reasons: [] },
  trust: { count: 0, brands: new Set(), sample_reasons: [] },
  range: { count: 0, brands: new Set(), sample_reasons: [] },
  delivery: { count: 0, brands: new Set(), sample_reasons: [] },
  installation: { count: 0, brands: new Set(), sample_reasons: [] },
  returns: { count: 0, brands: new Set(), sample_reasons: [] },
  warranty: { count: 0, brands: new Set(), sample_reasons: [] },
  finance: { count: 0, brands: new Set(), sample_reasons: [] },
  reviews: { count: 0, brands: new Set(), sample_reasons: [] },
  availability: { count: 0, brands: new Set(), sample_reasons: [] },
  speed: { count: 0, brands: new Set(), sample_reasons: [] },
  other: { count: 0, brands: new Set(), sample_reasons: [] }
};

// Track what signals competitors use vs client
const clientSignals = new Set();
const competitorSignals = {};

allReports.forEach(report => {
  const clientName = report.client_name || 'markselectrical';

  // Client signals - safely access
  if (report.client_visibility?.mentioned && report.client_visibility?.evidence_cited) {
    clientSignals.add(report.client_visibility.evidence_cited);
  }

  // Competitor signals - safely access ranked_retailers
  const rankedRetailers = report.ranked_retailers || [];

  rankedRetailers.forEach(retailer => {
    const signal = retailer.evidence_type || 'other';
    const brand = retailer.name || '';

    if (!brand) return;

    // Check if this is the client
    const brandLower = brand.toLowerCase();
    const isClient = brandLower.includes('marks') || 
                     brand === 'Marks Electrical' || 
                     brand === clientName;

    if (!isClient) {
      evidenceSignalMap[signal].count++;
      evidenceSignalMap[signal].brands.add(brand);

      if (evidenceSignalMap[signal].sample_reasons.length < 3 && retailer.reason) {
        evidenceSignalMap[signal].sample_reasons.push(retailer.reason);
      }

      if (!competitorSignals[brand]) {
        competitorSignals[brand] = {};
      }
      competitorSignals[brand][signal] = (competitorSignals[brand][signal] || 0) + 1;
    }
  });
});

// Convert Sets to Arrays for JSON
Object.keys(evidenceSignalMap).forEach(signal => {
  evidenceSignalMap[signal].brands = Array.from(evidenceSignalMap[signal].brands);
  // Calculate percentage based on total mentions (10 retailers per query)
  const totalPossibleMentions = allReports.length * 10;
  evidenceSignalMap[signal].percentage = totalPossibleMentions > 0 
    ? Math.round((evidenceSignalMap[signal].count / totalPossibleMentions) * 100)
    : 0;
});

// Identify gaps
const allSignals = Object.keys(evidenceSignalMap);
const clientMissingSignals = allSignals.filter(s => 
  !clientSignals.has(s) && evidenceSignalMap[s].count > 0
);

// Build strategic opportunities
const strategicOpportunities = clientMissingSignals
  .sort((a, b) => evidenceSignalMap[b].count - evidenceSignalMap[a].count)
  .slice(0, 5)
  .map(signal => {
    const data = evidenceSignalMap[signal];
    return {
      value_prop: signal,
      frequency: `${data.percentage}% of LLM responses cite this`,
      leading_competitors: data.brands.slice(0, 3),
      example_messaging: data.sample_reasons[0] || `Emphasize ${signal}`,
      priority: data.count > allReports.length * 3 ? 'HIGH' : 'MEDIUM',
      action: `Create content emphasizing ${signal}. Example: "${data.sample_reasons[0] || 'N/A'}"`
    };
  });

// Build competitor landscape
const competitorLandscape = Object.entries(competitorMap)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 15)
  .map(([brand, count]) => ({
    brand,
    mentions_across_queries: count,
    mention_rate: Math.round((count / allReports.length) * 100) + "%"
  }));

// Build category performance
const performanceByCategory = Object.entries(categoryMap).map(([category, stats]) => ({
  category,
  total_queries: stats.total,
  times_mentioned: stats.mentioned,
  mention_rate: Math.round((stats.mentioned / stats.total) * 100) + "%",
  avg_position: stats.position_count > 0
    ? Math.round((stats.position_sum / stats.position_count) * 10) / 10
    : null
}));

// Build best/worst queries
const bestQueries = allReports
  .filter(r => r.client_visibility?.mentioned)
  .sort((a, b) => {
    const posA = a.client_visibility?.position || 999;
    const posB = b.client_visibility?.position || 999;
    return posA - posB;
  })
  .slice(0, 5)
  .map(r => ({
    query: r.query_text,
    category: r.query_category,
    llm_position: r.client_visibility?.position,
    competitors_in_response: r.total_competitors || 0
  }));

const worstQueries = allReports
  .filter(r => !r.client_visibility?.mentioned)
  .slice(0, 5)
  .map(r => ({
    query: r.query_text,
    category: r.query_category,
    top_competitors_mentioned: (r.competitors_mentioned || []).slice(0, 3),
    total_competitors: r.total_competitors || 0
  }));

return {
  report_generated_at: new Date().toISOString(),
  client: {
    name: allReports[0]?.client_name || 'markselectrical',
    total_queries_analyzed: allReports.length
  },

  aggregate_metrics: {
    total_times_mentioned_by_llm: mentionCount,
    llm_mention_rate: Math.round((mentionCount / allReports.length) * 100) + "%",
    avg_position_when_mentioned: mentionCount > 0 ? Math.round((totalPosition / mentionCount) * 10) / 10 : null,
    times_in_top_3: top3Count,
    top_3_rate: Math.round((top3Count / allReports.length) * 100) + "%"
  },

  // NEW: Evidence Signal Intelligence
  evidence_landscape: evidenceSignalMap,

  // NEW: What client is missing
  value_prop_gaps: strategicOpportunities,
  client_cited_for: Array.from(clientSignals),
  client_never_cited_for: clientMissingSignals,

  // NEW: Competitor positioning
  competitor_strengths: Object.entries(competitorSignals)
    .map(([brand, signals]) => {
      const signalEntries = Object.entries(signals);
      return {
        brand,
        total_mentions: Object.values(signals).reduce((a, b) => a + b, 0),
        primary_strength: signalEntries.length > 0 ? signalEntries.sort((a, b) => b[1] - a[1])[0] : null,
        all_signals: signals
      };
    })
    .sort((a, b) => b.total_mentions - a.total_mentions)
    .slice(0, 10),

  // Existing data
  competitor_landscape: competitorLandscape,
  performance_by_category: performanceByCategory,
  best_queries: bestQueries,
  worst_queries: worstQueries,
  detailed_results: allReports
};

const aggregateData = $('Aggregate All Results2').first().json;

// Generate a structured summary without using LLM
const report = {
  executive_summary: generateExecutiveSummary(aggregateData),
  key_findings: generateKeyFindings(aggregateData),
  competitor_analysis: generateCompetitorAnalysis(aggregateData),
  value_prop_gaps: aggregateData.value_prop_gaps || [],
  recommendations: generateRecommendations(aggregateData)
};

function generateExecutiveSummary(data) {
  const metrics = data.aggregate_metrics;
  const topCompetitor = data.competitor_landscape[0];

  return `Marks Electrical was mentioned in ${metrics.llm_mention_rate} of test queries, with an average position of #${metrics.avg_position_when_mentioned || 'N/A'} when mentioned. ${topCompetitor ? `${topCompetitor.brand} dominates LLM responses with ${topCompetitor.mention_rate} mention rate.` : ''} ${data.client_never_cited_for.length > 0 ? `Key opportunity: Client is never cited for ${data.client_never_cited_for.slice(0, 3).join(', ')}.` : ''}`;
}

function generateKeyFindings(data) {
  const findings = [];

  // Finding 1: Overall performance
  const mentionRate = parseInt(data.aggregate_metrics.llm_mention_rate);
  if (mentionRate === 0) {
    findings.push("CRITICAL: Client has zero LLM visibility across all test queries");
  } else if (mentionRate < 30) {
    findings.push(`LOW VISIBILITY: Only ${data.aggregate_metrics.llm_mention_rate} mention rate`);
  } else if (mentionRate < 60) {
    findings.push(`MODERATE VISIBILITY: ${data.aggregate_metrics.llm_mention_rate} mention rate`);
  } else {
    findings.push(`STRONG VISIBILITY: ${data.aggregate_metrics.llm_mention_rate} mention rate`);
  }

  // Finding 2: Top competitor dominance
  if (data.competitor_landscape.length > 0) {
    const top3 = data.competitor_landscape.slice(0, 3);
    findings.push(`Top competitors: ${top3.map(c => `${c.brand} (${c.mention_rate})`).join(', ')}`);
  }

  // Finding 3: Evidence signal gaps
  if (data.value_prop_gaps.length > 0) {
    const topGap = data.value_prop_gaps[0];
    findings.push(`Biggest gap: ${topGap.value_prop.toUpperCase()} - ${topGap.frequency}, leading brands: ${topGap.leading_competitors.slice(0, 2).join(', ')}`);
  }

  // Finding 4: Category performance
  const categoryPerf = data.performance_by_category || [];
  const bestCategory = categoryPerf.sort((a, b) => parseInt(b.mention_rate) - parseInt(a.mention_rate))[0];
  const worstCategory = categoryPerf.sort((a, b) => parseInt(a.mention_rate) - parseInt(b.mention_rate))[0];

  if (bestCategory) {
    findings.push(`Best category: ${bestCategory.category} (${bestCategory.mention_rate})`);
  }
  if (worstCategory && worstCategory !== bestCategory) {
    findings.push(`Worst category: ${worstCategory.category} (${worstCategory.mention_rate})`);
  }

  return findings;
}

function generateCompetitorAnalysis(data) {
  const competitors = data.competitor_strengths || [];

  return competitors.slice(0, 5).map(comp => {
    const primaryStrength = comp.primary_strength;
    const strengthName = primaryStrength ? primaryStrength[0] : 'unknown';
    const strengthCount = primaryStrength ? primaryStrength[1] : 0;

    return {
      brand: comp.brand,
      total_mentions: comp.total_mentions,
      primary_value_prop: strengthName,
      strength_frequency: strengthCount,
      insight: `${comp.brand} leads on ${strengthName.toUpperCase()} (cited ${strengthCount} times)`
    };
  });
}

function generateRecommendations(data) {
  const recommendations = [];

  // Recommendation 1: Address top value prop gaps
  if (data.value_prop_gaps && data.value_prop_gaps.length > 0) {
    data.value_prop_gaps.slice(0, 3).forEach((gap, i) => {
      recommendations.push({
        priority: gap.priority,
        category: 'Content & Messaging',
        action: `Emphasize ${gap.value_prop.toUpperCase()} in homepage and category pages`,
        rationale: `Competitors are cited for this ${gap.frequency}. Leading brands: ${gap.leading_competitors.slice(0, 2).join(', ')}`,
        example: gap.example_messaging,
        expected_impact: `Could capture additional mentions in ${gap.value_prop}-focused queries`
      });
    });
  }

  // Recommendation 2: FAQ Schema
  const queriesNotMentioned = data.worst_queries || [];
  if (queriesNotMentioned.length > 0) {
    const commonQuestionTypes = [...new Set(queriesNotMentioned.map(q => q.category))];
    recommendations.push({
      priority: 'HIGH',
      category: 'Technical SEO',
      action: 'Add FAQ Schema to key landing pages',
      rationale: `Client not mentioned in ${queriesNotMentioned.length} queries. FAQ schema improves LLM parsing.`,
      example: `Create FAQ sections for: ${commonQuestionTypes.slice(0, 3).join(', ')} queries`,
      expected_impact: 'Increases likelihood of being cited for question-based queries'
    });
  }

  // Recommendation 3: Comparison content
  const topCompetitors = data.competitor_landscape.slice(0, 3);
  if (topCompetitors.length > 0) {
    recommendations.push({
      priority: 'MEDIUM',
      category: 'Content Creation',
      action: 'Create comparison pages for top competitors',
      rationale: `${topCompetitors[0].brand} mentioned in ${topCompetitors[0].mention_rate} of queries`,
      example: `Create pages: "Marks Electrical vs ${topCompetitors.map(c => c.brand).join('", "Marks Electrical vs ')}"`,
      expected_impact: 'Captures comparison-focused queries and establishes competitive positioning'
    });
  }

  // Recommendation 4: Evidence-based content
  const evidenceLandscape = data.evidence_landscape || {};
  const topSignals = Object.entries(evidenceLandscape)
    .sort((a, b) => b[1].count - a[1].count)
    .slice(0, 3)
    .filter(([signal, data]) => data.count > 0);

  if (topSignals.length > 0) {
    recommendations.push({
      priority: 'MEDIUM',
      category: 'Content Enhancement',
      action: 'Structure content around high-value evidence signals',
      rationale: `LLMs most frequently cite: ${topSignals.map(([s, d]) => `${s} (${d.percentage}%)`).join(', ')}`,
      example: `Add dedicated sections for each signal with clear headers and structured content`,
      expected_impact: 'Aligns content with what LLMs look for when making recommendations'
    });
  }

  return recommendations;
}

return {
  output: report.executive_summary,
  key_findings: report.key_findings,
  competitor_analysis: report.competitor_analysis,
  value_prop_gaps: report.value_prop_gaps,
  recommendations: report.recommendations,
  full_data: aggregateData
};
